// Case-split on the antecedent of the implication so that, inside the
// branch, both run-1 and run-2 ensures clauses are available as path
// conditions on the same `self_@.dom()` witness. Then explicitly assert
// the cross-run set equality so z3 instantiates `to_set()` /
// `map_values` triggers on both `r1@` and `r2@` and chains through the
// shared `self_@.dom()`.
if (r1@.map_values(|e: EndPoint| e@).to_set() == self_@.dom())
    && (r2@.map_values(|e: EndPoint| e@).to_set() == self_@.dom()) {
    assert(r1@.map_values(|e: EndPoint| e@).to_set()
        == r2@.map_values(|e: EndPoint| e@).to_set());
}
